#[test]
fn test_schema_has_feed_functions() {
    let schema_json = get_schema_from_wasm();
    let schema: serde_json::Value =
        serde_json::from_str(&schema_json).expect("Failed to parse schema JSON");

    let functions = schema["functions"]
        .as_array()
        .expect("functions should be an array");
    let fn_names: Vec<&str> = functions
        .iter()
        .map(|f| f["name"].as_str().unwrap())
        .collect();

    assert!(fn_names.contains(&"items"), "missing items");
    assert!(fn_names.contains(&"item_ids"), "missing item_ids");

    // Verify the schema shows () as output (the Rust return type)
    let items_fn = functions
        .iter()
        .find(|f| f["name"] == "items")
        .expect("items not found");
    assert_eq!(
        items_fn["output"].as_str().unwrap(),
        "()",
        "items should have () as output in schema"
    );
}

#[test]
fn test_feed_function_decode_uses_feed_type() {
    use types::{Item, ItemId};

    let mut driver = DataDriverWasm::new();

    // Create test data: (ItemId, Item) tuple
    let item_id = ItemId(1);
    let item = Item {
        id: item_id,
        value: 1000,
        active: true,
    };

    // Serialize the tuple using rkyv
    let rkyv_data = rkyv::to_bytes::<_, 256>(&(item_id, item)).expect("Failed to serialize tuple");

    // Decode using the data-driver — uses the feed_type "(ItemId, Item)"
    let decoded = driver
        .decode_output("items", &rkyv_data)
        .expect("Failed to decode items output");

    // Verify we got an array (tuple serializes as array in JSON)
    assert!(
        decoded.is_array(),
        "Expected array (tuple), got: {decoded:?}"
    );

    let arr = decoded.as_array().unwrap();
    assert_eq!(arr.len(), 2, "Expected 2-element tuple");

    // First element is ItemId
    assert!(
        !arr[0].is_null(),
        "First element (ItemId) should not be null: {decoded:?}"
    );

    // Second element is Item struct
    assert!(arr[1].is_object(), "Second element should be Item object");
    assert!(arr[1]["value"].is_number(), "Item should have value field");
    assert_eq!(arr[1]["value"], 1000);
    assert_eq!(arr[1]["active"], true);
}

#[test]
fn test_feed_function_simple_type_decode() {
    use types::ItemId;

    let mut driver = DataDriverWasm::new();

    let item_id = ItemId(42);

    let rkyv_data = rkyv::to_bytes::<_, 256>(&item_id).expect("Failed to serialize ItemId");

    // Decode using the data-driver — uses the feed_type "ItemId"
    let decoded = driver
        .decode_output("item_ids", &rkyv_data)
        .expect("Failed to decode item_ids output");

    // ItemId should not be null
    assert!(
        !decoded.is_null(),
        "Expected non-null ItemId, got null. The feeds attribute is not working!"
    );

    // ItemId(42) should decode to 42
    assert_eq!(decoded, serde_json::json!(42));
}

// =============================================================================
// Tests for decode_event (using actual contract events)
// =============================================================================

use std::sync::LazyLock;

use dusk_core::abi::ContractId;
use dusk_core::dusk;
use dusk_core::signatures::bls::{PublicKey as AccountPublicKey, SecretKey as AccountSecretKey};
use rand::SeedableRng;
use rand::rngs::StdRng;
use test_session::TestSession;
use types::{Item, ItemId};

const CONTRACT_BYTECODE: &[u8] =
    include_bytes!("../../../target/contract/wasm32-unknown-unknown/release/test_contract.wasm");
const CONTRACT_ID: ContractId = ContractId::from_bytes([1; 32]);
const DEPLOYER: [u8; 64] = [0u8; 64];
const INITIAL_BALANCE: u64 = dusk(1_000.0);

static OWNER_SK: LazyLock<AccountSecretKey> = LazyLock::new(|| {
    let mut rng = StdRng::seed_from_u64(0x5EAF00D);
    AccountSecretKey::random(&mut rng)
});
static OWNER_PK: LazyLock<AccountPublicKey> = LazyLock::new(|| AccountPublicKey::from(&*OWNER_SK));

/// Set up a contract session for event tests.
fn setup_contract_session() -> TestSession {
    let mut session = TestSession::instantiate(vec![(&*OWNER_PK, INITIAL_BALANCE)], vec![]);

    session
        .deploy(
            CONTRACT_BYTECODE,
            dusk_vm::ContractData::builder()
                .owner(DEPLOYER)
                .init_arg(&(*OWNER_PK,))
                .contract_id(CONTRACT_ID),
        )
        .expect("Deploying test contract should succeed");

    session
}

#[test]
fn test_decode_event_counter_reset() {
    // 1. Call the contract to emit a real event
    let mut session = setup_contract_session();
    let receipt = session
        .call_public::<_, ()>(&OWNER_SK, CONTRACT_ID, "reset_counter", &())
        .expect("reset_counter should succeed");

    // 2. Extract the event from the receipt
    assert!(
        !receipt.events.is_empty(),
        "reset_counter should emit an event"
    );
    let event = &receipt.events[0];
    assert_eq!(event.topic, "counter_reset");

    // 3. Decode the event using the data-driver
    let mut driver = DataDriverWasm::new();
    let decoded = driver
        .decode_event(&event.topic, &event.data)
        .expect("Failed to decode CounterReset event");

    // CounterReset is a unit struct, may serialize to null or empty array
    assert!(
        decoded.is_null() || (decoded.is_array() && decoded.as_array().unwrap().is_empty()),
        "CounterReset should serialize to null or empty array, got: {decoded:?}"
    );
}

#[test]
fn test_decode_event_item_added() {
    // 1. Call the contract to emit a real item_added event
    let mut session = setup_contract_session();

    let item = Item {
        id: ItemId(1),
        value: 1000,
        active: true,
    };

    let receipt = session
        .call_public::<_, ()>(&OWNER_SK, CONTRACT_ID, "add_item", &item)
        .expect("add_item should succeed");

    // 2. Find the item_added event
    let event = receipt
        .events
        .iter()
        .find(|e| e.topic == "item_added")
        .expect("add_item should emit item_added event");

    // 3. Decode the event using the data-driver
    let mut driver = DataDriverWasm::new();
    let decoded = driver
        .decode_event(&event.topic, &event.data)
        .expect("Failed to decode Item event");

    // Verify the decoded fields match what we sent
    assert!(decoded.is_object(), "Item event should be an object");
    assert_eq!(decoded["value"], 1000);
    assert_eq!(decoded["active"], true);
}

