// =============================================================================
// Schema detail verification tests
// =============================================================================

#[test]
fn test_schema_function_input_output_types() {
    let schema_json = get_schema_from_wasm();
    let schema: serde_json::Value =
        serde_json::from_str(&schema_json).expect("Failed to parse schema JSON");

    let functions = schema["functions"]
        .as_array()
        .expect("functions should be an array");

    // Test counter: no input, returns u64
    let counter = functions
        .iter()
        .find(|f| f["name"] == "counter")
        .expect("counter should exist");
    assert_eq!(counter["input"], "()", "counter input should be ()");
    assert_eq!(counter["output"], "u64", "counter output should be u64");

    // Test init: takes PublicKey, returns ()
    let init = functions
        .iter()
        .find(|f| f["name"] == "init")
        .expect("init should exist");
    let init_input = init["input"].as_str().unwrap();
    assert!(
        init_input.contains("PublicKey"),
        "init input should contain PublicKey: {init_input}"
    );
    assert_eq!(init["output"], "()", "init output should be ()");

    // Test set_counter: takes u64, returns ()
    let set_counter = functions
        .iter()
        .find(|f| f["name"] == "set_counter")
        .expect("set_counter should exist");
    assert_eq!(
        set_counter["input"], "u64",
        "set_counter input should be u64"
    );
    assert_eq!(
        set_counter["output"], "()",
        "set_counter output should be ()"
    );

    // Test add_item: takes Item type, returns ()
    let add_item = functions
        .iter()
        .find(|f| f["name"] == "add_item")
        .expect("add_item should exist");
    let add_item_input = add_item["input"].as_str().unwrap();
    assert!(
        add_item_input.contains("Item"),
        "add_item input should contain Item: {add_item_input}"
    );
    assert_eq!(add_item["output"], "()", "add_item output should be ()");

    // Test get_item: takes ItemId, returns Option<Item>
    let get_item = functions
        .iter()
        .find(|f| f["name"] == "get_item")
        .expect("get_item should exist");
    let get_item_input = get_item["input"].as_str().unwrap();
    let get_item_output = get_item["output"].as_str().unwrap();
    assert!(
        get_item_input.contains("ItemId"),
        "get_item input should contain ItemId: {get_item_input}"
    );
    assert!(
        get_item_output.contains("Option") && get_item_output.contains("Item"),
        "get_item output should be Option<Item>: {get_item_output}"
    );
}

